	/* softmax */
	float max_s = scores[0];
	for (int i = 1; i < 8; i++)
		if (scores[i] > max_s) max_s = scores[i];

	float sum_exp = 0.0f;
	for (int i = 0; i < 8; i++) {
		scores[i] = expf(scores[i] - max_s);
		sum_exp += scores[i];
	}

	int best = 0;
	float best_prob = 0.0f;
	for (int i = 0; i < 8; i++) {
		output[i] = scores[i] / sum_exp;
		if (output[i] > best_prob) {
			best_prob = output[i];
			best = i;
		}
	}

	return best;
